const raw = $input.first().json;
const body = raw.body ?? raw;

const required = ['roleDescription', 'cvText', 'candidateName'];
const missing = required.filter((k) => !body[k] || String(body[k]).trim() === '');
if (missing.length) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const recordId = body.recordId ?? null;
const writeToAttio = body.writeToAttio !== false && Boolean(recordId);

return [{
  json: {
    recordId,
    roleDescription: String(body.roleDescription).trim(),
    cvText: String(body.cvText).trim(),
    candidateName: String(body.candidateName).trim(),
    linkedinUrl: body.linkedinUrl ?? null,
    roleTitle: body.roleTitle ?? null,
    writeToAttio,
    enableAudioSummary: body.enableAudioSummary === true,
    receivedAt: new Date().toISOString(),
  },
}];

const input = $('Normalize input').first().json;
return [{
  json: {
    recordId: input.recordId,
    roleDescription: input.roleDescription,
    cvText: input.cvText,
    candidateName: input.candidateName,
    linkedinUrl: input.linkedinUrl,
    roleTitle: input.roleTitle,
    approve: false,
  },
}];

const review = $('Build full review').first().json;
const decision = $('Wait for approval').first().json;

return [{
  json: {
    status: 'rejected',
    candidateName: review.candidateName,
    fitScore: review.fitScore,
    fitTier: review.fitTier,
    reviewSummary: review.reviewSummary,
    reviewerNotes: decision['Reviewer notes (optional)'] ?? null,
    message: 'Research completed but not approved — nothing written to Attio or sent externally.',
    reviewMarkdown: review.reviewMarkdown,
  },
}];

const review = $('Build full review').first().json;
const input = review.input;
return [{
  json: {
    recordId: input.recordId,
    roleDescription: input.roleDescription,
    cvText: input.cvText,
    candidateName: input.candidateName,
    linkedinUrl: input.linkedinUrl,
    roleTitle: input.roleTitle,
    approve: true,
  },
}];

const review = $('Build full review').first().json;
const decision = $('Wait for approval').first().json;
const attio = $('Attio write-back API').first().json;

return [{
  json: {
    status: 'approved',
    mode: 'attio_writeback',
    candidateName: review.candidateName,
    recordId: review.recordId,
    fitScore: attio.fit?.score ?? review.fitScore,
    fitTier: attio.fit?.tier ?? review.fitTier,
    twoLiner: attio.bundle?.twoLiner ?? review.twoLiner,
    enableAudioSummary: review.enableAudioSummary,
    reviewerNotes: decision['Reviewer notes (optional)'] ?? null,
    message: 'Approved — fit fields and HM note written to Attio.',
    reviewMarkdown: review.reviewMarkdown,
    clientSubmittalDraft: review.clientSubmittalDraft,
    candidateEmailDraft: review.candidateEmailDraft,
    ttsScript: review.ttsScript,
    attioResult: attio,
    _reviewNode: 'Build full review',
    _baseNode: 'Attio approved base',
  },
}];

const base = $('Standalone approved base').first().json;
const ttsItems = $('SLNG TTS API (standalone)').all();
const audio = ttsItems.length ? ttsItems[0].json : null;

return [{
  json: {
    status: base.status,
    mode: base.mode,
    candidateName: base.candidateName,
    fitScore: base.fitScore,
    fitTier: base.fitTier,
    twoLiner: base.twoLiner,
    pros: base.pros,
    cons: base.cons,
    gapAnalysis: base.gapAnalysis,
    hmNote: base.hmNote,
    clientSubmittalDraft: base.clientSubmittalDraft,
    candidateEmailDraft: base.candidateEmailDraft,
    webBullets: base.webBullets,
    reviewerNotes: base.reviewerNotes,
    reviewMarkdown: base.reviewMarkdown,
    reviewSummary: base.reviewSummary,
    audioSummary: audio ? {
      id: audio.id,
      url: audio.url,
      downloadUrl: audio.downloadUrl,
      contentType: audio.contentType,
    } : null,
    message: audio
      ? `${base.message} Listen: ${audio.url}`
      : base.message,
  },
}];

const base = $('Attio approved base').first().json;
const ttsItems = $('SLNG TTS API (attio)').all();
const audio = ttsItems.length ? ttsItems[0].json : null;

return [{
  json: {
    status: base.status,
    mode: base.mode,
    candidateName: base.candidateName,
    recordId: base.recordId,
    fitScore: base.fitScore,
    fitTier: base.fitTier,
    twoLiner: base.twoLiner,
    reviewerNotes: base.reviewerNotes,
    reviewMarkdown: base.reviewMarkdown,
    clientSubmittalDraft: base.clientSubmittalDraft,
    candidateEmailDraft: base.candidateEmailDraft,
    attioResult: base.attioResult,
    audioSummary: audio ? {
      id: audio.id,
      url: audio.url,
      downloadUrl: audio.downloadUrl,
      contentType: audio.contentType,
    } : null,
    message: audio
      ? `${base.message} Listen: ${audio.url}`
      : base.message,
  },
}];
